const axios = require('axios'); // Importing AXIOS library which is used to make HTTP requests 
const cheerio = require('cheerio');//Import Cheerio, an HTML parser that can be used with jQuery style selectors. It allows us to manipulate the DOM of web pages in a very similar way than jQuery does for selecting elements on websites using data-attributes and CSS classes as selector strings 
const metadataExtractor = async (url) => { //Defining function named 'metadataExtractor' which takes url parameter  
    try{//Starting Try block to handle any exceptions that might occur during execution of the code inside it. If an exception occurs, control will jump out from this catch and execute whatever is in its body 
        const response = await axios.get(url); //Making HTTP GET request using AXIOS library  
         if (response.status !==200) {//If the status of our http requests isn't successful we will throw an error message and stop execution here   
            console.log('Error fetching URL', url, 'Response: ', response);  //Logs Error Message along with Url which caused it to fail  
             return;     }     
        const html = response.data ;//Assigning the HTML data received from server into variable named "html"   
         var $ = cheerio.load(html) ;//Load Cheerio and parse our 'HTML' using load method  //Cheerio is a library that parses an HTML string, creating a jQuery style object which allows us to select elements on the page  
        const title = $('head > meta[name="title"]').attr("content");    //Selects first <meta> tag with name attribute as "Title", and returns its content.  If no such element exists it will return undefined or an empty string if not provided a value for 'Content'  
        const description = $('head > meta[name="description"]').attr("content");//Same thing here, but we are looking at the <meta> tag with name attribute as "Description", and returns its content.  If no such element exists it will return undefined or an empty string if not provided a value for 'Content'  
        const ogTitle = $('head > meta[property="og:title"]').attr("content");//Same thing here, but we are looking at the <meta> tag with property attribute as "og:title", and returns its content.  If no such element exists it will return undefined or an empty string if not provided a value for 'Content'  
        const ogDescription = $('head > meta[property="og:description"]').attr("content");//Same thing here, but we are looking at the <meta> tag with property attribute as "og:title", and returns its content.  If no such element exists it will return undefined or an empty string if not provided a value for 'Content'  
        console.log('Title', title); //Logs Title fetched from web page   
         console.log('Description ', description) ;// Log the Description of Web Page    
          console.log ('og:title :->', ogTitle );  // log Open Graph meta tags if exist otherwise it will return undefined or an empty string  
           console.log( 'OG Desc:->>' , ogDescription);    //Logs open graph description fetched from web page    
        } catch (error) {//Catch block to handle any exceptions that might occur during execution of the code inside it 
          console.log('Error occurred: ', error );  
       };     
};